// get_health — Gateway health from live E2E test data
// ============================================================
// Source: credential_health DataTable (populated by E2E suite)
// Fallback: api_registry_v2 for domains without test data
// Zero hardcoded values
// ============================================================

const apiKey = $vars.N8N_INTERNAL_API_KEY;
const host = $vars.N8N_HOST;
const healthTableId = $vars.CREDENTIAL_HEALTH_TABLE_ID;
const registryId = $vars.REGISTRY_V2_API_TABLE_ID;
const base = host + '/api/v1';

async function fetchAllRows(tableId) {
  let rows = [], cursor = '', more = true;
  while (more) {
    const url = base + '/data-tables/' + tableId + '/rows?limit=250' + (cursor ? '&cursor=' + cursor : '');
    const resp = await this.helpers.httpRequest({ method: 'GET', url, headers: { 'X-N8N-API-KEY': apiKey } });
    rows = rows.concat(resp.data || []);
    cursor = resp.nextCursor || '';
    more = !!resp.nextCursor && resp.data && resp.data.length > 0;
  }
  return rows;
}

try {
  // 1. Fetch credential_health — dedup by highest ID per domain
  const healthRows = await fetchAllRows(healthTableId);
  const healthByDomain = {};
  for (const r of healthRows) {
    const d = r.domain;
    if (!d) continue;
    if (!healthByDomain[d] || r.id > healthByDomain[d].id) healthByDomain[d] = r;
  }

  // 2. Fetch registry for complete domain list
  const regRows = await fetchAllRows(registryId);
  const regByDomain = {};
  for (const r of regRows) {
    const d = r.api_name;
    if (!d) continue;
    const enabled = r.enabled === true || r.enabled === 'true';
    if (!regByDomain[d]) {
      regByDomain[d] = { enabled, category: r.category || 'other' };
    } else if (enabled) {
      regByDomain[d].enabled = true;
    }
  }

  // 3. Build health report
  const healthy = [];
  const degraded = [];
  const down = [];
  const allDomains = new Set([...Object.keys(healthByDomain), ...Object.keys(regByDomain)]);

  for (const domain of [...allDomains].sort()) {
    const health = healthByDomain[domain];
    const reg = regByDomain[domain];

    if (!reg || !reg.enabled) {
      if (health) down.push({ api: domain, status: 'disabled', source: 'registry' });
      continue;
    }

    if (health && health.status) {
      const entry = {
        api: domain,
        status: health.status,
        actions_tested: health.actions_tested || 0,
        actions_passed: health.actions_passed || 0,
        last_checked: health.last_checked_at || 'unknown',
        source: health.check_source || 'e2e_suite'
      };
      if (health.error_message) entry.error = String(health.error_message).slice(0, 150);
      if (health.error_type && health.error_type !== 'none') entry.error_type = health.error_type;

      if (health.status === 'healthy') healthy.push(entry);
      else if (health.status === 'degraded') degraded.push(entry);
      else down.push(entry);
    } else {
      degraded.push({ api: domain, status: 'untested', source: 'registry_only', category: reg.category });
    }
  }

  const lastRun = Object.values(healthByDomain).reduce((latest, r) => {
    return (!latest || (r.last_checked_at && r.last_checked_at > latest)) ? r.last_checked_at : latest;
  }, null);

  return JSON.stringify({
    summary: healthy.length + ' healthy, ' + degraded.length + ' degraded/untested, ' + down.length + ' down/disabled',
    healthy_count: healthy.length,
    degraded_count: degraded.length,
    down_count: down.length,
    total_domains: allDomains.size,
    healthy: healthy.map(h => h.api),
    degraded,
    down,
    data_source: 'credential_health DataTable (E2E-tested)',
    last_e2e_run: lastRun,
    note: 'Live E2E test results. For manual retest: POST /webhook/health-check-v2'
  });
} catch (error) {
  return JSON.stringify({ error: 'Health check failed: ' + (error.message || 'unknown error') });
}

