  let rows = [];
  let cursor = '';
  let hasMore = true;
  while (hasMore) {
    const url = `${n8nHost}/api/v1/data-tables/${tableId}/rows?limit=250${cursor ? '&cursor=' + cursor : ''}`;
    const resp = await this.helpers.httpRequest({
