    const cutoff = new Date(Date.now() - days * 86400000);
    rows = rows.filter(r => new Date(r.timestamp || r.createdAt) >= cutoff);
  }

  // Filter by provider/domain
  if (provider) {
    rows = rows.filter(r => (r.domain || '').toLowerCase() === provider.toLowerCase());
  }

  // Filter by client (enforced for non-admin, optional for admin)
  if (effectiveClientFilter) {
    rows = rows.filter(r => (r.client || '').toLowerCase() === effectiveClientFilter.toLowerCase());
  }

