  const byDomain = {};
  for (const r of rows) {
    const key = r.domain || 'unknown';
    if (!byDomain[key]) byDomain[key] = { domain: key, total_tokens: 0, est_cost_usd: 0, requests: 0 };
    byDomain[key].total_tokens += Number(r.total_tokens || 0);
    byDomain[key].est_cost_usd += Number(r.est_cost_usd || 0);
    byDomain[key].requests += 1;
  }

  // Aggregate by client (admin view)
  const byClient = {};
  for (const r of rows) {
    const key = r.client || 'unknown';
    if (!byClient[key]) byClient[key] = { client: key, total_tokens: 0, est_cost_usd: 0, requests: 0 };
    byClient[key].total_tokens += Number(r.total_tokens || 0);
    byClient[key].est_cost_usd += Number(r.est_cost_usd || 0);
    byClient[key].requests += 1;
  }

  // Calculate totals
  let totalCost = 0, totalTokens = 0, totalRequests = rows.length;
  for (const v of Object.values(byDomain)) {
    totalCost += v.est_cost_usd;
    totalTokens += v.total_tokens;
  }

  const result = {
    period_days: days,
    filter_provider: provider || 'all',
    filter_client: effectiveClientFilter || 'all',
