    total_tokens: totalTokens,
    total_est_cost_usd: Math.round(totalCost * 1000000) / 1000000,
    by_domain: Object.values(byDomain).map(d => ({ ...d, est_cost_usd: Math.round(d.est_cost_usd * 1000000) / 1000000 })).sort((a,b) => b.est_cost_usd - a.est_cost_usd),
