// Validates the MCP bearer token against tenant_auth DataTable
// Returns: { authorized: true, clientId, permissionLevel, ... } or throws/returns error
const crypto = require('crypto');

async function authenticateRequest(context, requestedDomain) {
  const n8nHost = $vars.N8N_HOST;
  const internalKey = $vars.N8N_INTERNAL_API_KEY;
  const tenantAuthTableId = $vars.TENANT_AUTH_TABLE_ID;
  const bearerToken = $vars.MCP_GATEWAY_BEARER_TOKEN;

  if (!tenantAuthTableId || !bearerToken) {
    // Fail-closed: if config missing, deny
    return { authorized: false, error: 'Auth service unavailable: missing configuration' };
  }

  function verifyApiKey(plainTextKey, storedHash) {
    const parts = storedHash.split(':');
    if (parts.length !== 3 || parts[0] !== 'sha256') return false;
    const salt = parts[1];
    const expectedHash = parts[2];
    const actualHash = crypto.createHash('sha256').update(salt + plainTextKey).digest('hex');
    return actualHash === expectedHash;
  }

  try {
    // Fetch tenant_auth rows
    let allRows = [];
    let cursor = '';
    let hasMore = true;
    while (hasMore) {
      const url = `${n8nHost}/api/v1/data-tables/${tenantAuthTableId}/rows?limit=250${cursor ? '&cursor=' + cursor : ''}`;
      const resp = await context.helpers.httpRequest({
        method: 'GET', url,
        headers: { 'X-N8N-API-KEY': internalKey }
      });
      allRows = allRows.concat(resp.data || []);
      cursor = resp.nextCursor || '';
      hasMore = !!resp.nextCursor && resp.data && resp.data.length > 0;
    }

    // Find matching tenant
    let tenantMatch = null;
    for (const row of allRows) {
      if (!row.api_key_hash) continue;
      if (verifyApiKey(bearerToken, row.api_key_hash)) {
        tenantMatch = row;
        break;
      }
    }

    if (!tenantMatch) {
      // Bearer token not in tenant_auth — might still be valid via n8n's built-in auth
      // Allow through with minimal context (backward compat during migration)
      return { authorized: true, clientId: 'mcp_default', permissionLevel: 'read_write', authSource: 'bearer_passthrough', isAdmin: false };
    }

    // Check active
    if (tenantMatch.active !== true && tenantMatch.active !== 'true') {
      return { authorized: false, error: 'API key deactivated' };
    }

    // Check expiry
    if (tenantMatch.expires_at && tenantMatch.expires_at !== 'never') {
      if (new Date(tenantMatch.expires_at) < new Date()) {
        return { authorized: false, error: 'API key expired' };
      }
    }

    // Parse domain permissions
    let permissions = {};
    try { permissions = JSON.parse(tenantMatch.domain_permissions || '{}'); } catch(e) {}

    // Check domain permission if a domain was requested
    let permissionLevel = permissions['*'] || null;
    if (requestedDomain && requestedDomain !== '*') {
      permissionLevel = permissions[requestedDomain] || permissions['*'] || null;
      if (!permissionLevel) {
        return { authorized: false, error: 'Domain not authorized: ' + requestedDomain };
      }
    }

    // Admin alert — logs + Slack notification
    const isAdmin = tenantMatch.client_id === 'ascend_admin';
    if (isAdmin) {
      const alertMsg = '⚠️ ADMIN KEY USED via MCP — client_id: ascend_admin, domain: ' + (requestedDomain || 'n/a') + ', timestamp: ' + new Date().toISOString();
      console.log(alertMsg);
      const slackUrl = $vars.SLACK_WEBHOOK_URL;
      if (slackUrl) {
        try {
          await context.helpers.httpRequest({
            method: 'POST', url: slackUrl,
            headers: { 'Content-Type': 'application/json' },
            body: { text: alertMsg },
            timeout: 3000
          });
        } catch(e) { /* Slack alert is best-effort */ }
      }
    }

    return {
      authorized: true,
      clientId: tenantMatch.client_id,
      permissionLevel: permissionLevel || 'read',
      rateLimitPerMinute: tenantMatch.rate_limit_per_minute || 60,
      credentialSet: tenantMatch.credential_set || 'default',
      authSource: 'tenant_auth',
      isAdmin
    };
  } catch (e) {
    // Fail-closed on error
    return { authorized: false, error: 'Auth service unavailable: ' + e.message };
  }
}
