// ===== SSRF PROTECTION UTILITIES =====
function validatePath(path) {
  if (!path || typeof path !== 'string') {
    return { valid: false, reason: 'Path is required and must be a string' };
  }
  if (path.includes('..') || path.includes('//')) {
    return { valid: false, reason: 'Path traversal detected' };
  }
  if (path.includes('\0') || path.includes('%00')) {
    return { valid: false, reason: 'Null byte in path' };
  }
  if (!path.startsWith('/')) {
    path = '/' + path;
  }
  return { valid: true, path: path };
}

function buildSafeUrl(baseUrl, path) {
  const validated = validatePath(path);
  if (!validated.valid) return { url: null, error: validated.reason };
  const cleanBase = baseUrl.replace(/\/+$/, '');
  return { url: cleanBase + validated.path, error: null };
}

function validateRequestBody(body) {
  if (!body) return { valid: true };
  const bodyStr = typeof body === 'string' ? body : JSON.stringify(body);
  if (bodyStr.length > 1048576) {
    return { valid: false, reason: 'Request body exceeds 1MB limit' };
  }
  return { valid: true };
}
// ===== END SSRF PROTECTION =====

// ===== PERMISSION CHECKER (F1: 3-tier permission model) =====
// Permission levels: read < read_write < admin
// read: GET + low risk only
// read_write: all methods except high-risk (DELETE bulk, dangerous ops)
// admin: everything including high-risk
function checkPermission(permissionLevel, method, riskLevel) {
  if (!permissionLevel) return { allowed: false, reason: 'No permission level assigned' };

  if (permissionLevel === 'admin') return { allowed: true };

  if (permissionLevel === 'read_write') {
    if (riskLevel === 'high') {
      return { allowed: false, reason: "Permission 'read_write' insufficient for high-risk operations (requires admin)" };
    }
    return { allowed: true };
  }

  if (permissionLevel === 'read') {
    if (method !== 'GET' && method !== 'HEAD' && method !== 'OPTIONS') {
      return { allowed: false, reason: "Permission 'read' only allows GET/HEAD/OPTIONS methods" };
    }
    if (riskLevel && riskLevel !== 'low') {
      return { allowed: false, reason: "Permission 'read' only allows low-risk endpoints" };
    }
    return { allowed: true };
  }

  return { allowed: false, reason: "Unknown permission level: '" + permissionLevel + "'" };
}
// ===== END PERMISSION CHECKER =====


