const AI_DOMAINS = new Set(['anthropic','openai','gemini','deepseek','groq','openrouter','perplexity','bedrock','ollama','huggingface','mistral','qwen']);

async function logCostForAI(domain, responseData, clientId) {
  if (!AI_DOMAINS.has(domain)) return;

  const costTrackerTableId = $vars.AI_COST_TRACKER_TABLE_ID;
  const n8nHost = $vars.N8N_HOST;
  const apiKey = $vars.N8N_INTERNAL_API_KEY;
  if (!costTrackerTableId) return;

  // Extract token counts — different providers use different fields
  let prompt_tokens = 0, completion_tokens = 0, total_tokens = 0;
  let model = 'unknown';

  const data = typeof responseData === 'string' ? (() => { try { return JSON.parse(responseData); } catch(e) { return {}; } })() : (responseData || {});

  if (data.usage) {
    prompt_tokens = data.usage.prompt_tokens || 0;
    completion_tokens = data.usage.completion_tokens || 0;
    total_tokens = data.usage.total_tokens || (prompt_tokens + completion_tokens);
  } else if (data.usageMetadata) {
    prompt_tokens = data.usageMetadata.promptTokenCount || 0;
    completion_tokens = data.usageMetadata.candidatesTokenCount || 0;
    total_tokens = data.usageMetadata.totalTokenCount || (prompt_tokens + completion_tokens);
  }

  if (data.model) model = data.model;
  else if (data.choices && data.choices[0] && data.choices[0].model) model = data.choices[0].model;

  // Estimate cost per 1M tokens
  const costPer1M = {
    'anthropic': { input: 3.00, output: 15.00 },
    'openai': { input: 2.50, output: 10.00 },
    'groq': { input: 0.05, output: 0.08 },
    'deepseek': { input: 0.14, output: 0.28 },
    'openrouter': { input: 1.00, output: 3.00 },
    'gemini': { input: 0.075, output: 0.30 },
    'perplexity': { input: 0.20, output: 0.60 },
    'huggingface': { input: 0.10, output: 0.20 },
    'mistral': { input: 0.25, output: 0.75 },
    'qwen': { input: 0.14, output: 0.28 },
    'ollama': { input: 0, output: 0 },
    'bedrock': { input: 2.00, output: 8.00 }
  };

  const rates = costPer1M[domain] || { input: 1.00, output: 3.00 };
  const est_cost_usd = ((prompt_tokens * rates.input) + (completion_tokens * rates.output)) / 1000000;

  const action = 'passthrough';

  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${n8nHost}/api/v1/data-tables/${costTrackerTableId}/rows`,
      headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
      body: { data: [{
        domain,
        action,
        client: clientId,
        model,
        prompt_tokens,
        completion_tokens,
        total_tokens,
        est_cost_usd: Math.round(est_cost_usd * 1000000) / 1000000,
        timestamp: new Date().toISOString(),
        date: new Date().toISOString().split('T')[0]
      }] },
      timeout: 5000
    });
  } catch (e) {
    // Fail-open for cost logging — don't block the request
    console.log('Cost log warning: ' + e.message);
  }
}
