// ===== RATE LIMITER =====
async function checkRateLimit(clientId, rateLimitPerMinute) {
  if (!rateLimitPerMinute || rateLimitPerMinute <= 0) return { allowed: true };
  const n8nHost = $vars.N8N_HOST;
  const apiKey = $vars.N8N_INTERNAL_API_KEY;
  const rateLimitTableId = $vars.RATE_LIMIT_TABLE_ID;
  if (!rateLimitTableId) return { allowed: true }; // Skip if not configured

  const now = new Date();
  const currentMinute = now.toISOString().substring(0, 16); // e.g. "2026-03-14T10:05"

  try {
    // Fetch current minute's rows for this client
    const rows = await fetchAllRows.call(this, rateLimitTableId);
    const clientRows = rows.filter(r => r.client === clientId && r.hour === currentMinute);

    if (clientRows.length >= rateLimitPerMinute) {
      return { allowed: false, current: clientRows.length, limit: rateLimitPerMinute };
    }

    // Increment counter — add a row
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${n8nHost}/api/v1/data-tables/${rateLimitTableId}/rows`,
      headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
      body: { data: [{ client: clientId, domain: 'passthrough', hour: currentMinute, ts: now.toISOString() }] }
    });

    return { allowed: true, current: clientRows.length + 1, limit: rateLimitPerMinute };
  } catch (e) {
    // Fail-closed on rate limit check failure
    return { allowed: true }; // Degrade to allow — rate limiting is approximate
  }
}
// ===== END RATE LIMITER =====

// ===== MAIN: execute_passthrough =====
const requestId = crypto.randomUUID();
const startTime = Date.now();

// Parse input
let parsedInput = {};
try {
  if (typeof query === 'string' && query.trim()) {
    parsedInput = JSON.parse(query);
  }
} catch(e) {
  parsedInput = { input: query };
}
const $input = { item: { json: parsedInput } };

const domain = $input.item.json.domain;
const path = $input.item.json.path;
const method = ($input.item.json.method || 'GET').toUpperCase();
const body = $input.item.json.body || null;
const queryParams = $input.item.json.query_params || {};
const extraHeaders = $input.item.json.headers || {};

// --- Validate required params ---
if (!domain || !path) {
  return JSON.stringify({ 
    error: 'domain and path are required. Use list_capabilities to discover endpoints.',
    request_id: requestId 
  });
}

const VALID_METHODS = ['GET', 'POST', 'PUT', 'DELETE', 'PATCH', 'HEAD', 'OPTIONS'];
if (!VALID_METHODS.includes(method)) {
  return JSON.stringify({ error: `Invalid HTTP method: ${method}`, request_id: requestId });
}

// --- Auth check ---
const authResult = await authenticateRequest.call(this, this, domain);
if (!authResult.authorized) {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId || 'unknown', domain, 
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: authResult.error, credential_set: '', status_code: 403,
    response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ error: authResult.error, code: 403, request_id: requestId });
}

// --- F1: Unified 3-tier permission check (pre-catalog, method-level) ---
// This catches obvious method-level violations early, before catalog lookup
const WRITE_METHODS = ['POST', 'PUT', 'DELETE', 'PATCH'];
if (WRITE_METHODS.includes(method) && authResult.permissionLevel === 'read') {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: "Permission 'read' only allows GET/HEAD/OPTIONS methods", credential_set: authResult.credentialSet || '',
    status_code: 403, response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ 
    error: "Permission 'read' only allows GET/HEAD/OPTIONS methods (domain: " + domain + ")", 
    code: 403, request_id: requestId 
  });
}

// --- Rate limit check ---
const rateResult = await checkRateLimit.call(this, authResult.clientId, authResult.rateLimitPerMinute);
if (!rateResult.allowed) {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: `Rate limit exceeded: ${rateResult.current}/${rateResult.limit} per minute`,
    credential_set: authResult.credentialSet || '', status_code: 429,
    response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ 
    error: `Rate limit exceeded (${rateResult.current}/${rateResult.limit} per minute)`,
    code: 429, request_id: requestId 
  });
}

// --- SSRF: Validate path ---
const pathCheck = validatePath(path);
if (!pathCheck.valid) {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: pathCheck.reason, credential_set: authResult.credentialSet || '',
    status_code: 400, response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ error: pathCheck.reason, code: 400, request_id: requestId });
}

// --- Body size check ---
const bodyCheck = validateRequestBody(body);
if (!bodyCheck.valid) {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: bodyCheck.reason, credential_set: authResult.credentialSet || '',
    status_code: 413, response_time_ms: Date.now() - startTime
