// --- Step 1: Look up domain in api_registry_v2 ---
const registryTableId = $vars.REGISTRY_V2_API_TABLE_ID;
if (!registryTableId) {
  return JSON.stringify({ error: 'Gateway configuration error: REGISTRY_V2_API_TABLE_ID missing', request_id: requestId });
