    denial_reason: `No catalog entry for domain '${domain}'`,
    credential_set: authResult.credentialSet || '', status_code: 404,
    response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ error: `No catalog entry for domain '${domain}'`, request_id: requestId });
}

let endpoints = [];
try {
  endpoints = JSON.parse(catalogRow.endpoints || '[]');
} catch (e) {
  return JSON.stringify({ error: `Failed to parse catalog endpoints for ${domain}`, request_id: requestId });
}

// Path matching: exact match first, then pattern match for {param} placeholders
const normalizedPath = pathCheck.path; // Already validated and normalized
const matchedEndpoint = endpoints.find(e => {
  if (e.method !== method) return false;
  // Exact match
  if (e.path === normalizedPath) return true;
  // Pattern match: replace {param} with regex [^/]+
  const pattern = e.path.replace(/\{[^}]+\}/g, '[^/]+');
  const regex = new RegExp('^' + pattern + '$');
  return regex.test(normalizedPath);
});

if (!matchedEndpoint) {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: `Endpoint ${method} ${path} not in catalog for '${domain}'`,
    credential_set: authResult.credentialSet || '', status_code: 403,
    response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ 
    error: `Endpoint ${method} ${path} not in catalog for '${domain}'`,
    hint: 'Use list_capabilities to see available endpoints',
    request_id: requestId 
  });
}

// Check executable flag
if (!matchedEndpoint.executable) {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: `Endpoint ${method} ${path} is not executable (documentation only)`,
    credential_set: authResult.credentialSet || '', status_code: 403,
    response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ 
    error: `Endpoint ${method} ${path} is not executable (documentation only)`,
    request_id: requestId 
  });
}

// F1: Unified 3-tier permission check (post-catalog, with risk_level)
const riskLevel = matchedEndpoint.risk_level || 'low';
const permCheck = checkPermission(authResult.permissionLevel, method, riskLevel);
if (!permCheck.allowed) {
  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${path}`, method, decision: 'denied',
    denial_reason: permCheck.reason,
    credential_set: authResult.credentialSet || '', status_code: 403,
    response_time_ms: Date.now() - startTime
  });
  return JSON.stringify({ error: permCheck.reason, code: 403, request_id: requestId });
}

// --- Step 3: Build safe URL ---
const baseUrl = domainRow.base_url;
const urlResult = buildSafeUrl(baseUrl, normalizedPath);
if (urlResult.error) {
  return JSON.stringify({ error: urlResult.error, request_id: requestId });
}

// --- Step 4: Inject credentials ---
const requestHeaders = { ...extraHeaders };
// Don't let client override auth headers
delete requestHeaders['Authorization'];
delete requestHeaders['authorization'];
delete requestHeaders['x-api-key'];
delete requestHeaders['X-Api-Key'];

const authType = domainRow.auth_type;
const authHeader = domainRow.auth_header || '';
const authPrefix = domainRow.auth_prefix || '';
const credentialVar = domainRow.credential_var || '';

// Build query params for passthrough
let finalQueryParams = { ...queryParams };

if (authType === 'none') {
  // No auth needed (e.g., Ollama via Tailscale)
} else if (authType === 'query') {
  // API key in query param (Gemini, SEMrush)
  const apiKeyValue = credentialVar ? $vars[credentialVar] : null;
  if (!apiKeyValue) {
    return JSON.stringify({ 
      error: `Credentials not configured for domain '${domain}' (variable: ${credentialVar || 'none'})`,
      request_id: requestId 
    });
  }
  // For Gemini: key param; for SEMrush: key param
  finalQueryParams['key'] = apiKeyValue;
} else if (authType === 'header' || authType === 'api_key_header') {
  const apiKeyValue = credentialVar ? $vars[credentialVar] : null;
  if (!apiKeyValue) {
    return JSON.stringify({ 
      error: `Credentials not configured for domain '${domain}' (variable: ${credentialVar || 'none'})`,
      request_id: requestId 
    });
  }
  const headerName = authHeader || 'Authorization';
  if (authPrefix) {
    requestHeaders[headerName] = authPrefix + ' ' + apiKeyValue;
  } else {
    requestHeaders[headerName] = apiKeyValue;
  }
} else if (authType === 'basic') {
  // Basic auth (Gong) — credential_var points to access key, companion secret via naming convention
  const accessKey = credentialVar ? $vars[credentialVar] : null;
  // Try multiple naming patterns for the secret key variable:
  //   GONG_ACCESS_KEY_KAHUNA -> GONG_SECRET_KEY_KAHUNA, CRED_GONG_KAHUNA
  const secretCandidates = [
    credentialVar ? credentialVar.replace('ACCESS_KEY', 'SECRET_KEY') : '',
    credentialVar ? 'CRED_' + credentialVar.replace('_ACCESS_KEY', '').replace(/_KAHUNA$/, '_KAHUNA') : '',
    credentialVar ? 'CRED_' + domain.toUpperCase() + '_' + (credentialVar.split('_').pop() || '') : ''
  ].filter(Boolean);
  let secretKey = '';
  for (const candidate of secretCandidates) {
    if ($vars[candidate]) { secretKey = $vars[candidate]; break; }
  }
  if (!accessKey) {
    return JSON.stringify({ 
      error: `Credentials not configured for domain '${domain}' (variable: ${credentialVar || 'none'})`,
      request_id: requestId 
    });
  }
  const basicAuth = Buffer.from(accessKey + ':' + secretKey).toString('base64');
  requestHeaders['Authorization'] = 'Basic ' + basicAuth;
} else if (authType === 'credential') {
  // n8n managed credential (GitHub) — use the credential_id from registry
  // For GitHub, the token is in a PAT variable
  const githubPat = $vars.GITHUB_PAT || $vars.GITHUB_TOKEN || '';
  if (!githubPat) {
    return JSON.stringify({ 
      error: `Credentials not configured for domain '${domain}' (no GITHUB_PAT variable)`,
      hint: 'Set GITHUB_PAT variable in n8n with a valid Personal Access Token',
      request_id: requestId 
    });
  }
  requestHeaders['Authorization'] = 'Bearer ' + githubPat;
} else {
  return JSON.stringify({ 
    error: `Unsupported auth type '${authType}' for domain '${domain}'`,
    request_id: requestId 
  });
}

// Add required headers for specific domains
if (domain === 'anthropic') {
  requestHeaders['anthropic-version'] = '2023-06-01';
}
if (domain === 'notion') {
  requestHeaders['Notion-Version'] = '2022-06-28';
}
if (!requestHeaders['Content-Type'] && body) {
  requestHeaders['Content-Type'] = 'application/json';
}

// --- Step 5: Forward request ---
let response;
try {
  const httpConfig = {
    method: method,
    url: urlResult.url,
    headers: requestHeaders,
    returnFullResponse: true,
    followRedirects: false,
    timeout: 30000
  };

  if (method !== 'GET' && method !== 'HEAD' && body) {
    httpConfig.body = body;
  }

  if (Object.keys(finalQueryParams).length > 0) {
    httpConfig.qs = finalQueryParams;
  }

  response = await this.helpers.httpRequest(httpConfig);
} catch (httpError) {
  const responseTime = Date.now() - startTime;
  const errorStatus = httpError.statusCode || httpError.response?.statusCode || 0;
  const errorBody = httpError.response?.body || httpError.message || 'Request failed';

  await logAudit.call(this, {
    request_id: requestId, client_id: authResult.clientId, domain,
    action_or_endpoint: `${method} ${normalizedPath}`, method, decision: 'allowed',
    denial_reason: '', credential_set: authResult.credentialSet || '',
    status_code: errorStatus, response_time_ms: responseTime
  });

  // Return the upstream error to the client
  return JSON.stringify({
    request_id: requestId,
    domain: domain,
    status_code: errorStatus,
    error: typeof errorBody === 'string' ? errorBody : JSON.stringify(errorBody),
    response_time_ms: responseTime
  });
}

// --- Step 6: Audit log ---
const responseTime = Date.now() - startTime;
const statusCode = response.statusCode || response.status || 200;

await logAudit.call(this, {
  request_id: requestId, client_id: authResult.clientId, domain,
  action_or_endpoint: `${method} ${normalizedPath}`, method, decision: 'allowed',
  denial_reason: '', credential_set: authResult.credentialSet || '',
  status_code: statusCode, response_time_ms: responseTime
});

// --- Step 7: Sanitize response ---
// Strip any auth headers from response (shouldn't normally appear, but defense-in-depth)
let responseData = response.body || response.data || '';
if (typeof responseData === 'string') {
  try { responseData = JSON.parse(responseData); } catch(e) { /* keep as string */ }
}

// --- Step 8: Log cost for AI domains (F2) ---
await logCostForAI.call(this, domain, responseData, authResult.clientId);

// --- Step 9: Return result ---
return JSON.stringify({
  request_id: requestId,
  domain: domain,
  endpoint: `${method} ${normalizedPath}`,
  status_code: statusCode,
  data: responseData,
  response_time_ms: responseTime
});
